# Clean A* Pathfinding Implementation

After analyzing the obfuscated code, this is an **A* pathfinding algorithm** on a 2D grid with diagonal movement support. Here's a clean implementation:

```javascript
// Grid configuration
const GRID_WIDTH = 20;
const GRID_HEIGHT = 15;

const config = {
  penalty: "manhattan",
  diagonalCost: 1.414,
  straightCost: 1,
  maxIterations: 1000,
  wallDensity: 0.25,
};

// Generate grid with random walls (1 = wall, 0 = open)
const grid = [];
for (let y = 0; y < GRID_HEIGHT; y++) {
  grid[y] = [];
  for (let x = 0; x < GRID_WIDTH; x++) {
    grid[y][x] = Math.random() < config.wallDensity ? 1 : 0;
  }
}

// Define start and goal
const start = { x: 0, y: 0 };
const goal = { x: GRID_WIDTH - 1, y: GRID_HEIGHT - 1 };

// Ensure start and goal are not walls
grid[start.y][start.x] = 0;
grid[goal.y][goal.x] = 0;

// Heuristic: Manhattan or Euclidean distance
function heuristic(a, b) {
  const dx = Math.abs(a.x - b.x);
  const dy = Math.abs(a.y - b.y);

  if (config.penalty === "manhattan") {
    return dx + dy;
  }
  return Math.sqrt(dx * dx + dy * dy);
}

// Get valid neighboring cells
function getNeighbors(node) {
  const neighbors = [];
  const directions = [
    { dx: 0, dy: -1, cost: config.straightCost },
    { dx: 0, dy: 1, cost: config.straightCost },
    { dx: -1, dy: 0, cost: config.straightCost },
    { dx: 1, dy: 0, cost: config.straightCost },
    { dx: -1, dy: -1, cost: config.diagonalCost },
    { dx: 1, dy: -1, cost: config.diagonalCost },
    { dx: -1, dy: 1, cost: config.diagonalCost },
    { dx: 1, dy: 1, cost: config.diagonalCost },
  ];

  for (const dir of directions) {
    const nx = node.x + dir.dx;
    const ny = node.y + dir.dy;

    if (
      nx >= 0 && nx < GRID_WIDTH &&
      ny >= 0 && ny < GRID_HEIGHT &&
      grid[ny][nx] === 0
    ) {
      neighbors.push({ x: nx, y: ny, moveCost: dir.cost });
    }
  }

  return neighbors;
}

// Create a unique string key for a node
function nodeKey(node) {
  return node.x + "," + node.y;
}

// A* pathfinding algorithm
function findPath(start, goal) {
  const openSet = {};      // Nodes to evaluate
  const closedSet = {};    // Already evaluated nodes
  const gScore = {};       // Cost from start to node
  const fScore = {};       // gScore + heuristic estimate
  const cameFrom = {};     // For path reconstruction

  const startKey = nodeKey(start);
  openSet[startKey] = start;
  gScore[startKey] = 0;
  fScore[startKey] = heuristic(start, goal);

  let iterations = 0;

  while (Object.keys(openSet).length > 0 && iterations < config.maxIterations) {
    iterations++;

    // Find node in openSet with lowest fScore
    let currentKey = null;
    let lowestF = Infinity;
    for (const key in openSet) {
      if (fScore[key] < lowestF) {
        lowestF = fScore[key];
        currentKey = key;
      }
    }

    const current = openSet[currentKey];

    // Check if we reached the goal
    if (current.x === goal.x && current.y === goal.y) {
      const path = [current];
      let traceKey = currentKey;
      while (cameFrom[traceKey]) {
        traceKey = cameFrom[traceKey];
        path.push(
          openSet[traceKey] || closedSet[traceKey] ||
          { x: parseInt(traceKey), y: parseInt(traceKey.split(",")[1]) }
        );
      }
      return { path, cost: gScore[currentKey], iterations };
    }

    // Move current from open to closed
    delete openSet[currentKey];
    closedSet[currentKey] = current;

    // Evaluate neighbors
    const neighbors = getNeighbors(current);
    for (const neighbor of neighbors) {
      const neighborKey = nodeKey(neighbor);

      if (closedSet[neighborKey]) continue;

      const tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + heuristic(neighbor, goal);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  return { path: [], cost: Infinity, iterations };
}

// Run the pathfinder
const result = findPath(start, goal);
console.log("Path length:", result.path.length, "Cost:", result.cost, "Iterations:", result.iterations);
```

## Key observations from the deobfuscated code:

- **Algorithm**: A* search with both Manhattan and Euclidean heuristic support
- **Grid**: 20×15 with 25% random wall density
- **Movement**: 8-directional (cardinal cost = 1, diagonal cost ≈ 1.414)
- **Iteration cap**: 1000 max iterations to prevent infinite loops
- **Path reconstruction**: Traces back through a `cameFrom` map from goal to start
